import random, socket, struct

def build_query(name,qtype=1):
    tid=random.randrange(0,65536)
    flags=0x0100
    qd=1
    header=struct.pack('!HHHHHH',tid,flags,qd,0,0,0)
    parts=name.split('.')
    qname=b''.join(bytes([len(p)])+p.encode() for p in parts)+b'\x00'
    question=qname+struct.pack('!HH',qtype,1)
    return tid, header+question

def parse_resp(data):
    tid,flags,qd,an,ns,ar=struct.unpack('!HHHHHH',data[:12])
    off=12
    for _ in range(qd):
        while data[off]!=0:
            off += 1+data[off]
        off += 1+4
    answers=[]
    for _ in range(an):
        # name ptr
        if data[off] & 0xc0 == 0xc0:
            off += 2
        else:
            while data[off]!=0:
                off += 1+data[off]
            off += 1
        typ,cls,ttl,rdlen=struct.unpack('!HHIH',data[off:off+10]); off+=10
        rdata=data[off:off+rdlen]; off+=rdlen
        answers.append((typ,cls,ttl,rdata))
    return answers

for ns in ['8.8.8.8','1.1.1.1']:
    for qtype,name in [(1,'A'),(28,'AAAA')]:
        tid,pkt=build_query('pwn.chal.csaw.io',qtype)
        s=socket.socket(socket.AF_INET,socket.SOCK_DGRAM)
        s.settimeout(5)
        try:
            s.sendto(pkt,(ns,53))
            data,_=s.recvfrom(2048)
            print('ns',ns,'type',name,'len',len(data))
            for typ,cls,ttl,rdata in parse_resp(data):
                if typ==1:
                    print(' A',socket.inet_ntoa(rdata))
                elif typ==28:
                    print(' AAAA',socket.inet_ntop(socket.AF_INET6,rdata))
                else:
                    print(' typ',typ,'rdlen',len(rdata))
        except Exception as e:
            print('ns',ns,'type',name,'err',e)
        finally:
            s.close()
PY

